mapper.select:
SELECT id as id, site_code AS siteCode, order_no AS orderNo, activity_id AS activityId, activity_name_i18n_code AS activityNameI18nCode, activity_template AS activityTemplate, user_id AS userId, user_account AS userAccount, super_agent_id AS superAgentId, vip_grade_code AS vipGradeCode, vip_rank_code AS vipRankCode, distribution_type AS distributionType, receive_start_time AS receiveStartTime, receive_end_time AS receiveEndTime, receive_status AS receiveStatus, final_rate AS finalRate, activity_amount AS activityAmount, currency_code AS currencyCode, running_water_multiple AS runningWaterMultiple, remark AS remark, receive_time AS receiveTime, created_time as createdTime, device_no AS deviceNo, ip AS ip, redbag_session_id AS redbagSessionId, reward_rank AS rewardRank, prize_type AS prizeType, prize_name AS prizeName, principal_amount AS principalAmount FROM site_activity_order_record_v2 a WHERE 1=1
AND a.created_time >= #{vo.startTime}
AND a.created_time <= #{vo.endTime}
AND a.receive_time >= #{vo.startTime}
AND a.receive_time <= #{vo.endTime}
AND a.id = #{vo.id}
AND a.id = #{vo.userId}
AND site_code = #{vo.siteCode}
AND activity_template = #{vo.activityTemplate}
AND receive_status = #{vo.receiveStatus}
AND activity_name_i18n_code IN
#{item}
AND a.activity_template = #{vo.activityTemplate}
AND a.order_no = #{vo.orderNo}
AND a.user_account = #{vo.userAccount}
ORDER BY a.receive_time asc
ORDER BY a.receive_time desc
ORDER BY a.receive_time DESC

select * from (

    SELECT
        a.site_code AS siteCode,
        a.order_no AS orderNo,
        a.activity_no AS activityNo,
        a.activity_template AS activityTemplate,
        b.activity_name_i18n_code AS activityNameI18nCode,
        a.user_id AS userId,
        a.user_account AS userAccount,
        a.account_type AS accountType,
        a.distribution_type AS receiveWay,
        a.receive_status AS receiveStatus,
        a.currency_code AS currencyCode,
        a.final_rate AS finalRate,
        a.activity_amount AS activityAmount,
        a.running_water_multiple AS runningWaterMultiple,
        (
        select acquire_num from site_activity_free_game_record t where t.order_no=a.order_no
        ) AS wheelNum,
        a.created_time AS sendTime,
        a.receive_time AS receiveTime,
        a.receive_end_time AS receiveEndTime,
        a.principal_amount AS principalAmount
    FROM
        site_activity_order_record_v2 a join
        site_activity_base_v2 b on a.activity_id=b.id
    where
        a.activity_template !='SPIN_WHEEL'

        AND a.site_code = #{vo.siteCode}


        AND a.created_time  >=  #{vo.sendStartTime}


        AND a.created_time  <=  #{vo.sendEndTime}



        AND a.receive_time  >=  #{vo.receiveStartTime}


        AND a.receive_time  <=  #{vo.receiveEndTime}




        AND a.receive_end_time  >=  #{vo.overStartTime}


        AND a.receive_end_time  <=  #{vo.overEndTime}



        AND a.user_account = #{vo.userAccount,jdbcType=VARCHAR}



        AND a.distribution_type = #{vo.receiveWay,jdbcType=VARCHAR}


        AND a.receive_status = #{vo.receiveStatus,jdbcType=VARCHAR}




        AND a.activity_template in

            #{activityTemplate}





        AND a.activity_template = #{vo.activityTemplate,jdbcType=VARCHAR}



        AND a.activity_no = #{vo.activityNo,jdbcType=VARCHAR}




        AND a.order_no = #{vo.activityOrderNo,jdbcType=VARCHAR}




        AND a.account_type = #{vo.accountType,jdbcType=VARCHAR}


    union ALL

    SELECT
        a.site_code AS siteCode,
        a.order_no AS orderNo,
        a.activity_no AS activityNo,
        a.activity_template AS activityTemplate,
        b.activity_name_i18n_code AS activityNameI18nCode,
        a.user_id AS userId,
        c.user_account AS userAccount,
        c.account_type AS accountType,
        '2' AS receiveWay,
        '1' AS receiveStatus,
        '' AS currencyCode,
        '' AS finalRate,
        bet_win_lose AS activityAmount,
        '' AS runningWaterMultiple,
        a.acquire_num AS wheelNum,
        a.created_time AS sendTime,
        a.created_time AS receiveTime,
        '' AS receiveEndTime,
        '' AS principalAmount
    from site_activity_free_game_record a join
        site_activity_base_v2 b on a.activity_id=b.id
    join user_info c on a.user_id=c.user_id
    where 1 =1

        AND a.site_code = #{vo.siteCode}


        AND a.created_time  >=  #{vo.sendStartTime}


        AND a.created_time  <=  #{vo.sendEndTime}



        AND a.created_time  >=  #{vo.receiveStartTime}


        AND a.created_time  <=  #{vo.receiveEndTime}




        AND a.created_time  >=  #{vo.overStartTime}


        AND a.created_time  <=  #{vo.overEndTime}



        AND c.user_account = #{vo.userAccount,jdbcType=VARCHAR}



        AND '2' = #{vo.receiveWay,jdbcType=VARCHAR}


        AND '1' = #{vo.receiveStatus,jdbcType=VARCHAR}




        AND a.activity_template in

            #{activityTemplate}





        AND a.activity_template = #{vo.activityTemplate,jdbcType=VARCHAR}



        AND a.activity_no = #{vo.activityNo,jdbcType=VARCHAR}



        AND a.order_no = #{vo.activityOrderNo,jdbcType=VARCHAR}



        AND c.account_type = #{vo.accountType,jdbcType=VARCHAR}


) as t


        order by t.sendTime


        order by t.receiveTime


        order by t.receiveEndTime





        order by t.sendTime desc


        order by t.receiveTime desc


        order by t.receiveEndTime desc
